import{_ as a,o as e,c as i,ae as t}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"디버깅","description":"디버깅 도구: 감시 모드, 원시 모델 스트림, 추론 누출 추적","frontmatter":{"title":"디버깅","description":"디버깅 도구: 감시 모드, 원시 모델 스트림, 추론 누출 추적"},"headers":[],"relativePath":"help/debugging.md","filePath":"help/debugging.md","lastUpdated":null}'),p={name:"help/debugging.md"};function n(l,s,o,d,h,c){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="디버깅" tabindex="-1">디버깅 <a class="header-anchor" href="#디버깅" aria-label="Permalink to &quot;디버깅&quot;">​</a></h1><p>이 페이지는 스트리밍 출력을 위한 디버깅 헬퍼를 다룹니다. 특히 프로바이더가 추론을 일반 텍스트에 혼합하는 경우를 다룹니다.</p><h2 id="런타임-디버그-재정의" tabindex="-1">런타임 디버그 재정의 <a class="header-anchor" href="#런타임-디버그-재정의" aria-label="Permalink to &quot;런타임 디버그 재정의&quot;">​</a></h2><p>채팅에서 <code>/debug</code>를 사용하여 <strong>런타임 전용</strong> 설정 재정의(메모리, 디스크 아님)를 설정하십시오. <code>/debug</code>는 기본적으로 비활성화되어 있습니다. <code>commands.debug: true</code>로 활성화하십시오. <code>openclaw.json</code>을 편집하지 않고 불명확한 설정을 토글해야 할 때 유용합니다.</p><p>예시:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/debug show</span></span>
<span class="line"><span>/debug set messages.responsePrefix=&quot;[openclaw]&quot;</span></span>
<span class="line"><span>/debug unset messages.responsePrefix</span></span>
<span class="line"><span>/debug reset</span></span></code></pre></div><p><code>/debug reset</code>은 모든 재정의를 지우고 디스크의 설정으로 돌아갑니다.</p><h2 id="게이트웨이-감시-모드" tabindex="-1">게이트웨이 감시 모드 <a class="header-anchor" href="#게이트웨이-감시-모드" aria-label="Permalink to &quot;게이트웨이 감시 모드&quot;">​</a></h2><p>빠른 반복을 위해 파일 감시자 아래에서 게이트웨이를 실행하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span></span></code></pre></div><p>이것은 다음으로 매핑됩니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/watch-node.mjs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre></div><p>감시자는 <code>src/</code> 아래의 빌드 관련 파일, 확장 소스 파일, 확장 <code>package.json</code> 및 <code>openclaw.plugin.json</code> 메타데이터, <code>tsconfig.json</code>, <code>package.json</code>, <code>tsdown.config.ts</code>에서 재시작합니다. 확장 메타데이터 변경 시 <code>tsdown</code> 재빌드를 강제하지 않고 게이트웨이가 재시작됩니다. 소스 및 설정 변경 시에는 먼저 <code>dist</code>를 재빌드합니다.</p><p><code>gateway:watch</code> 뒤에 게이트웨이 CLI 플래그를 추가하면 각 재시작 시 전달됩니다. 동일한 리포지토리/플래그 세트에 대해 동일한 감시 명령을 다시 실행하면 이제 중복 감시자 부모를 남기는 대신 이전 감시자를 대체합니다.</p><h2 id="개발-프로필-개발-게이트웨이-dev" tabindex="-1">개발 프로필 + 개발 게이트웨이 (--dev) <a class="header-anchor" href="#개발-프로필-개발-게이트웨이-dev" aria-label="Permalink to &quot;개발 프로필 + 개발 게이트웨이 (--dev)&quot;">​</a></h2><p>디버깅을 위해 상태를 격리하고 안전하고 일회용 설정을 가동하려면 개발 프로필을 사용하십시오. <strong>두 개</strong>의 <code>--dev</code> 플래그가 있습니다:</p><ul><li><strong>전역 <code>--dev</code> (프로필):</strong> <code>~/.openclaw-dev</code> 아래의 상태를 격리하고 게이트웨이 포트를 <code>19001</code>로 기본 설정합니다 (파생 포트도 이동).</li><li><strong><code>gateway --dev</code>: 게이트웨이에 누락된 경우 기본 설정 + 워크스페이스 자동 생성</strong>을 지시합니다 (BOOTSTRAP.md 건너뜀).</li></ul><p>권장 흐름 (개발 프로필 + 개발 부트스트랩):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:dev</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_PROFILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dev</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre></div><p>아직 전역 설치가 없다면 <code>pnpm openclaw ...</code>를 통해 CLI를 실행하십시오.</p><p>수행 내용:</p><ol><li><p><strong>프로필 격리</strong> (전역 <code>--dev</code>)</p><ul><li><code>OPENCLAW_PROFILE=dev</code></li><li><code>OPENCLAW_STATE_DIR=~/.openclaw-dev</code></li><li><code>OPENCLAW_CONFIG_PATH=~/.openclaw-dev/openclaw.json</code></li><li><code>OPENCLAW_GATEWAY_PORT=19001</code> (브라우저/캔버스가 그에 따라 이동)</li></ul></li><li><p><strong>개발 부트스트랩</strong> (<code>gateway --dev</code>)</p><ul><li>누락된 경우 최소 설정을 작성합니다 (<code>gateway.mode=local</code>, 루프백 바인딩).</li><li><code>agent.workspace</code>를 개발 워크스페이스로 설정합니다.</li><li><code>agent.skipBootstrap=true</code> (BOOTSTRAP.md 없음)를 설정합니다.</li><li>누락된 경우 워크스페이스 파일을 시드합니다: <code>AGENTS.md</code>, <code>SOUL.md</code>, <code>TOOLS.md</code>, <code>IDENTITY.md</code>, <code>USER.md</code>, <code>HEARTBEAT.md</code>.</li><li>기본 ID: <strong>C3-PO</strong> (프로토콜 드로이드).</li><li>개발 모드에서 채널 프로바이더를 건너뜁니다 (<code>OPENCLAW_SKIP_CHANNELS=1</code>).</li></ul></li></ol><p>초기화 흐름 (새로 시작):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:dev:reset</span></span></code></pre></div><p>참고: <code>--dev</code>는 <strong>전역</strong> 프로필 플래그이며 일부 실행기에서 소비됩니다. 명시적으로 지정해야 하는 경우 환경 변수 형식을 사용하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_PROFILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dev</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reset</span></span></code></pre></div><p><code>--reset</code>은 설정, 자격 증명, 세션, 개발 워크스페이스를 지우고 (<code>trash</code>를 사용, <code>rm</code> 아님) 기본 개발 설정을 다시 만듭니다.</p><p>팁: 비개발 게이트웨이가 이미 실행 중인 경우 (launchd/systemd), 먼저 중지하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre></div><h2 id="원시-스트림-로깅-openclaw" tabindex="-1">원시 스트림 로깅 (OpenClaw) <a class="header-anchor" href="#원시-스트림-로깅-openclaw" aria-label="Permalink to &quot;원시 스트림 로깅 (OpenClaw)&quot;">​</a></h2><p>OpenClaw는 필터링/형식 지정 전에 <strong>원시 어시스턴트 스트림</strong>을 기록할 수 있습니다. 추론이 일반 텍스트 델타로 도착하는지(별도의 사고 블록이 아닌지) 확인하는 가장 좋은 방법입니다.</p><p>CLI를 통해 활성화:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream</span></span></code></pre></div><p>선택적 경로 재정의:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway:watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --raw-stream-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.openclaw/logs/raw-stream.jsonl</span></span></code></pre></div><p>동등한 환경 변수:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_RAW_STREAM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_RAW_STREAM_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.openclaw/logs/raw-stream.jsonl</span></span></code></pre></div><p>기본 파일:</p><p><code>~/.openclaw/logs/raw-stream.jsonl</code></p><h2 id="원시-청크-로깅-pi-mono" tabindex="-1">원시 청크 로깅 (pi-mono) <a class="header-anchor" href="#원시-청크-로깅-pi-mono" aria-label="Permalink to &quot;원시 청크 로깅 (pi-mono)&quot;">​</a></h2><p>블록으로 파싱되기 전에 <strong>원시 OpenAI 호환 청크</strong>를 캡처하려면 pi-mono가 별도의 로거를 노출합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PI_RAW_STREAM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span></code></pre></div><p>선택적 경로:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PI_RAW_STREAM_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/.pi-mono/logs/raw-openai-completions.jsonl</span></span></code></pre></div><p>기본 파일:</p><p><code>~/.pi-mono/logs/raw-openai-completions.jsonl</code></p><blockquote><p>참고: 이것은 pi-mono의 <code>openai-completions</code> 프로바이더를 사용하는 프로세스에서만 방출됩니다.</p></blockquote><h2 id="안전-참고-사항" tabindex="-1">안전 참고 사항 <a class="header-anchor" href="#안전-참고-사항" aria-label="Permalink to &quot;안전 참고 사항&quot;">​</a></h2><ul><li>원시 스트림 로그에는 전체 프롬프트, 도구 출력, 사용자 데이터가 포함될 수 있습니다.</li><li>로그를 로컬에 유지하고 디버깅 후 삭제하십시오.</li><li>로그를 공유하는 경우 먼저 비밀과 개인 식별 정보를 제거하십시오.</li></ul>`,49)])])}const g=a(p,[["render",n]]);export{k as __pageData,g as default};
